from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismLoginTokenNode(BaseNode):
    name = "Prism: Login (Access Token)"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("access_token", "string", widget_type="text")
        self.add_output("success", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        token = inputs.get('access_token') or ''
        if core is None or not token:
            self.log_error("Need core and access_token.")
            return {'success': False}
        try:
            plugin = core.getPlugin('PrismInternals') if hasattr(core, 'getPlugin') else core.plugins.getPlugin('PrismInternals')
            if plugin is None:
                self.log_error("PrismInternals plugin not loaded.")
                return {'success': False}
            internals = getattr(plugin, 'internals', plugin)
            internals.login(accessToken=token)
            self.log_success("Logged in via access token.")
            await self.set_output('exec_out', True)
            return {'success': True}
        except Exception as e:
            self.log_error(f"login failed: {e}")
            return {'success': False}

def register_node():
    return PrismLoginTokenNode
